#include <iostream>

namespace metric { long long scale(long long value) { return value * 1000; } }
namespace binary { long long scale(long long value) { return value * 1024; } }

int main() {
    char mode{};
    long long value{};
    if (!(std::cin >> mode >> value)) return 1;
    if (mode == 'm') std::cout << metric::scale(value) << '\n';
    else if (mode == 'b') std::cout << binary::scale(value) << '\n';
    else std::cout << "invalid\n";
}
